// Normalize RSS item to standard format
const item = $input.item.json;

// Generate stable GUID
let guid = item.guid || item.id || item.link;
if (!guid) {
  const crypto = require('crypto');
  guid = crypto.createHash('md5').update((item.title || '') + (item.pubDate || '')).digest('hex');
}

// Detect source from link
let source = 'unknown';
if (item.link) {
  if (item.link.includes('prnewswire')) source = 'PRNewswire';
  else if (item.link.includes('globenewswire')) source = 'GlobeNewswire';
  else if (item.link.includes('businesswire')) source = 'BusinessWire';
}

// Extract ticker symbols
const text = [item.title, item.contentSnippet, item.content, item.description].filter(Boolean).join(' ');
const tickerPatterns = [
  /\b(?:NASDAQ|NYSE|AMEX|OTC)\s*[:\-]\s*([A-Z]{1,5})\b/gi,
  /\(([A-Z]{2,5})\)/g,
  /\$([A-Z]{2,5})\b/g
];

const tickers = new Set();
const excluded = ['FDA', 'CEO', 'CFO', 'COO', 'IPO', 'USA', 'NYSE', 'THE', 'FOR', 'AND', 'INC', 'LLC', 'LTD', 'PDF', 'SEC', 'CRL'];

for (const pattern of tickerPatterns) {
  let match;
  while ((match = pattern.exec(text)) !== null) {
    const ticker = match[1].toUpperCase();
    if (!excluded.includes(ticker) && ticker.length >= 2 && ticker.length <= 5) {
      tickers.add(ticker);
    }
  }
}

// Parse publication date
let pubDateISO = new Date().toISOString();
try {
  pubDateISO = item.isoDate || new Date(item.pubDate).toISOString();
} catch (e) {}

return {
  guid: guid,
  pubDate: item.pubDate || '',
  isoDate: item.isoDate || '',
  source: source,
  title: (item.title || '').slice(0, 500),
  link: item.link || '',
  content: (item.content || item.description || '').slice(0, 5000),
  contentSnippet: (item.contentSnippet || item.description || '').slice(0, 1000),
  pubDate: pubDateISO,
  tickers: Array.from(tickers).join(','),
  ingestedAt: new Date().toISOString(),
  status: 'new'
};

const rows = $input.all().map(i => i.json);

rows.sort((a, b) => new Date(b.pubDate) - new Date(a.pubDate));

const stats = {
  totalNews: rows.length,
  newItems: rows.filter(i => i.status === 'new').length,
  processedItems: rows.filter(i => i.status === 'processed').length,
  sourceCounts: {
    PRNewswire: rows.filter(i => i.source === 'PRNewswire').length,
    GlobeNewswire: rows.filter(i => i.source === 'GlobeNewswire').length,
    BusinessWire: rows.filter(i => i.source === 'BusinessWire').length,
  },
  lastUpdated: new Date().toISOString()
};

return [{
  json: {
    success: true,
    data: rows,
    stats,
    timestamp: new Date().toISOString()
  }
}];

// Parse FinBERT response and make Layer 1 decision
const finbertResponse = $input.item.json;
const prevData = $('Classify Event Type').item.json;

// Handle FinBERT response structure
let sentimentData = finbertResponse.body || finbertResponse;
if (Array.isArray(sentimentData) && Array.isArray(sentimentData[0])) {
  sentimentData = sentimentData[0];
}

// Find top sentiment
let topSentiment = { label: 'neutral', score: 0 };
if (Array.isArray(sentimentData)) {
  topSentiment = sentimentData.reduce((a, b) => (b.score > a.score ? b : a), sentimentData[0] || topSentiment);
}

const sentiment = topSentiment.label || 'neutral';
const confidence = topSentiment.score || 0;

// Decision logic
let decision = 'DROP';
let reasons = [];

// Always drop dilutive events
if (prevData.isDilutive) {
  reasons.push('Dilutive event (financing/CRL)');
}
// Drop negative sentiment with high confidence
else if (sentiment === 'negative' && confidence >= 0.55) {
  reasons.push('Negative sentiment (high confidence)');
}
// Proceed if positive sentiment
else if (sentiment === 'positive' && confidence >= 0.55) {
  decision = 'PROCEED';
  reasons.push('Positive sentiment confirmed');
}
// Proceed for high-value catalyst types even with neutral sentiment
else if (['FDA_APPROVAL', 'FDA_CLEARANCE', 'TRIAL_PHASE3', 'TRIAL_DATA', 'PARTNERSHIP', 'M_AND_A'].includes(prevData.eventType)) {
  decision = 'PROCEED';
  reasons.push('High-value catalyst event');
}
else {
  reasons.push('Neutral/weak sentiment, non-catalyst');
}

// Check for tickers
const tickers = (prevData.tickers || '').split(',').filter(t => t.trim());
if (tickers.length === 0 && decision === 'PROCEED') {
  decision = 'DROP';
  reasons.push('No ticker symbols found');
}

return {
  guid: prevData.guid,
  source: prevData.source,
  title: prevData.title,
  link: prevData.link,
  pubDate: prevData.pubDate,
  tickers: prevData.tickers,
  eventType: prevData.eventType,
  isDilutive: prevData.isDilutive,
  sentiment: sentiment,
  sentimentConfidence: Number(confidence.toFixed(4)),
  layer1Decision: decision,
  layer1Reasons: reasons.join('; '),
  processedAt: new Date().toISOString()
};

// Classify event type and prepare for FinBERT
const item = $input.item.json;
const text = [item.title, item.contentSnippet, item.content].filter(Boolean).join(' ').toLowerCase();

let eventType = 'OTHER';
let isDilutive = false;

// FDA Events
if (/fda\s+(approval|approved|clears|cleared|grants)/i.test(text)) {
  eventType = 'FDA_APPROVAL';
} else if (/510\(k\)|pma\s+approval/i.test(text)) {
  eventType = 'FDA_CLEARANCE';
} else if (/complete\s+response\s+letter|crl\b/i.test(text)) {
  eventType = 'FDA_CRL';
  isDilutive = true;
}
// Trial Results
else if (/phase\s*(3|iii|three)|pivotal/i.test(text)) {
  eventType = 'TRIAL_PHASE3';
} else if (/phase\s*(2|ii|two)/i.test(text)) {
  eventType = 'TRIAL_PHASE2';
} else if (/phase\s*(1|i|one)/i.test(text)) {
  eventType = 'TRIAL_PHASE1';
} else if (/topline|interim\s+(data|results)|primary\s+endpoint/i.test(text)) {
  eventType = 'TRIAL_DATA';
}
// Business Events
else if (/partnership|licensing|collaboration|agreement/i.test(text)) {
  eventType = 'PARTNERSHIP';
} else if (/merger|acquisition|acquire[ds]?|buyout/i.test(text)) {
  eventType = 'M_AND_A';
}
// Financing (dilutive)
else if (/offering|atm\s+program|pipe|private\s+placement|public\s+offering|stock\s+sale/i.test(text)) {
  eventType = 'FINANCING';
  isDilutive = true;
}

// Prepare text for FinBERT (max ~512 tokens)
const sentimentText = (item.title + '. ' + (item.contentSnippet || '')).slice(0, 2000);

return {
  ...item,
  eventType: eventType,
  isDilutive: isDilutive,
  sentimentText: sentimentText
};

// Calculate VWAP and Standard Deviation Bands

const item = $input.item.json;

// Skip items with missing required data
if (!item || !item.guid || !item.ticker) {
  return null;  // Filters out this item
}

const bars = item.bars || [];

// Preserve all original data
const eventData = {
  guid: item.guid,
  ticker: item.ticker,
  tickerCorrectedFrom: item.tickerCorrectedFrom,
  eventType: item.eventType,
  title: item.title,
  source: item.source,
  link: item.link,
  pubDate: item.pubDate,
  sentiment: item.sentiment,
  sentimentConfidence: item.sentimentConfidence,
  layer1Decision: item.layer1Decision,
  layer1Reasons: item.layer1Reasons,
  relativeVolume: item.relativeVolume,
  priceChangePct: item.priceChangePct,
  spreadTier: item.spreadTier,
  spreadPct: item.spreadPct,
  passesStage1: item.passesStage1,
  stage: item.stage,
  stage1PassedAt: item.stage1PassedAt,
  currentPrice: item.currentPrice,
  bid: item.bid,
  ask: item.ask,
  spread: item.spread
};

if (!bars || bars.length < 5) {
  return {
    ...eventData,
    stage2Status: 'INSUFFICIENT_DATA',
    stage2Error: 'Need at least 5 bars for VWAP',
    vwap: 0,
    vwapDeviation: 0,
    vwapPosition: null,
    vwapUpper1SD: 0,
    vwapLower1SD: 0,
    vwapUpper2SD: 0,
    vwapLower2SD: 0,
    stdDev: 0,
    aggressorRatio: 0,
    buyVolume: 0,
    sellVolume: 0,
    spreadTightening: false,
    snapshotAt: new Date().toISOString()
  };
}

// Calculate VWAP incrementally
let cumulativePV = 0;
let cumulativeVolume = 0;

for (const bar of bars) {
  const typicalPrice = (bar.h + bar.l + bar.c) / 3;
  const pv = typicalPrice * bar.v;
  cumulativePV += pv;
  cumulativeVolume += bar.v;
}

const currentVWAP = cumulativeVolume > 0 ? cumulativePV / cumulativeVolume : 0;
const currentPrice = eventData.currentPrice || bars[bars.length - 1]?.c || 0;

// Calculate intraday price standard deviation
const prices = bars.map(b => (b.h + b.l + b.c) / 3);
const mean = prices.reduce((sum, p) => sum + p, 0) / prices.length;
const variance = prices.reduce((sum, p) => sum + Math.pow(p - mean, 2), 0) / prices.length;
const stdDev = Math.sqrt(variance);

// VWAP Standard Deviation Bands
const vwapUpper1SD = currentVWAP + stdDev;
const vwapLower1SD = currentVWAP - stdDev;
const vwapUpper2SD = currentVWAP + (2 * stdDev);
const vwapLower2SD = currentVWAP - (2 * stdDev);

// VWAP Deviation %
const vwapDeviation = currentVWAP > 0 ? ((currentPrice - currentVWAP) / currentVWAP) * 100 : 0;

// VWAP Position
let vwapPosition = 'AT_VWAP';
if (currentPrice > vwapUpper2SD) vwapPosition = 'ABOVE_2SD';
else if (currentPrice > vwapUpper1SD) vwapPosition = 'ABOVE_1SD';
else if (currentPrice > currentVWAP) vwapPosition = 'ABOVE_VWAP';
else if (currentPrice < vwapLower2SD) vwapPosition = 'BELOW_2SD';
else if (currentPrice < vwapLower1SD) vwapPosition = 'BELOW_1SD';
else if (currentPrice < currentVWAP) vwapPosition = 'BELOW_VWAP';

// Aggressor Ratio (buy vs sell pressure)
let buyVolume = 0;
let sellVolume = 0;
for (let i = 1; i < bars.length; i++) {
  if (bars[i].c > bars[i-1].c) buyVolume += bars[i].v;
  else if (bars[i].c < bars[i-1].c) sellVolume += bars[i].v;
}
const totalDirectional = buyVolume + sellVolume;
const aggressorRatio = totalDirectional > 0 ? buyVolume / totalDirectional : 0.5;

// Spread tightening check
const recentBars = bars.slice(-5);
const earlierBars = bars.slice(0, 5);
const recentSpread = recentBars.reduce((sum, b) => sum + (b.h - b.l), 0) / recentBars.length;
const earlierSpread = earlierBars.reduce((sum, b) => sum + (b.h - b.l), 0) / earlierBars.length;
const spreadTightening = earlierSpread > 0 && recentSpread < earlierSpread;

return {
  ...eventData,
  stage2Status: 'CALCULATED',
  vwap: parseFloat(currentVWAP.toFixed(4)),
  vwapUpper1SD: parseFloat(vwapUpper1SD.toFixed(4)),
  vwapLower1SD: parseFloat(vwapLower1SD.toFixed(4)),
  vwapUpper2SD: parseFloat(vwapUpper2SD.toFixed(4)),
  vwapLower2SD: parseFloat(vwapLower2SD.toFixed(4)),
  vwapDeviation: parseFloat(vwapDeviation.toFixed(4)),
  vwapPosition: vwapPosition,
  stdDev: parseFloat(stdDev.toFixed(4)),
  aggressorRatio: parseFloat(aggressorRatio.toFixed(4)),
  buyVolume: buyVolume,
  sellVolume: sellVolume,
  spreadTightening: spreadTightening,
  snapshotAt: new Date().toISOString()
};

// Parse AI response
const data = $input.item.json;

let aiResponse = data.response || data.text || data.output || '';
const correctedTicker = aiResponse.trim().toUpperCase().replace(/[^A-Z]/g, '');

const originalData = { ...data };
delete originalData.response;
delete originalData.text;
delete originalData.output;

if (correctedTicker === 'SKIP' || correctedTicker === '' || correctedTicker.length > 5) {
  return {
    json: {
      ...originalData,
      ticker: null,
      tickerStatus: 'skipped',
      skipReason: 'AI could not find valid ticker',
      aiResponse: aiResponse
    }
  };
}

return {
  json: {
    ...originalData,
    ticker: correctedTicker,
    tickerStatus: 'ai_corrected',
    tickerCorrectedBy: 'AI',
    aiResponse: aiResponse,
    tickerValidated: true
  }
};

// =====================================================
// EXPAND TICKERS - Fixed Version
// Processes ALL input items, splits comma-separated tickers
// =====================================================

const allItems = $input.all();
const output = [];
const seenKeys = new Set();

for (const item of allItems) {
  const data = item.json;
  const tickersString = data.tickers || '';

  const tickers = tickersString
    .split(',')
    .map(t => t.trim().toUpperCase())
    .filter(t => t.length > 0 && t.length <= 5);

  if (tickers.length === 0) continue;

  for (const ticker of tickers) {
    const uniqueKey = `${data.guid}-${ticker}`;
    if (seenKeys.has(uniqueKey)) continue;
    seenKeys.add(uniqueKey);

    output.push({
      json: {
        guid: data.guid,
        ticker: ticker,
        source: data.source,
        title: data.title,
        link: data.link,
        pubDate: data.pubDate,
        contentSnippet: data.contentSnippet || '',
        eventType: data.eventType,
        sentiment: data.sentiment,
        sentimentConfidence: data.sentimentConfidence,
        layer1Decision: data.layer1Decision,
        layer1Reasons: data.layer1Reasons,
        processedAt: data.processedAt,
        id: data.id
      }
    });
  }
}

console.log(`Expanded ${allItems.length} items into ${output.length} ticker items`);
return output;

// =====================================================
// TICKER VALIDATION & CORRECTION - ENHANCED
// =====================================================

const items = $input.all();
const results = [];

// Comprehensive false positives
const FALSE_POSITIVES = new Set([
  // Medical conditions
  'HLHS', 'AIDS', 'COVID', 'PTSD', 'ADHD', 'COPD', 'ALS', 'NASH', 'PCOS',
  'TNBC', 'NSCLC', 'SCLC', 'CLL', 'AML', 'NHL', 'DLBCL', 'HER', 'BRCA',
  'EGFR', 'ALK', 'KRAS', 'NTRK', 'RET', 'MET', 'ROS', 'BRAF',
  'CAR', 'TCR', 'GVHD', 'CRS', 'DLT', 'MTD', 'ORR',
  // Regulatory
  'FDA', 'EMA', 'EPA', 'CDC', 'NIH', 'WHO', 'SEC', 'FTC',
  'NDA', 'BLA', 'ANDA', 'IND', 'CRL', 'PDUFA', 'REMS', 'EUA', 'PMA',
  'IPO', 'CEO', 'CFO', 'COO', 'CTO', 'CMO', 'CSO', 'EVP', 'SVP',
  'REIT', 'ETF', 'SPAC',
  // Scientific
  'RNA', 'DNA', 'MRNA', 'SIRNA', 'ASO', 'CRISPR', 'AAV', 'LNP',
  'HIV', 'HCV', 'HBV', 'HPV', 'RSV', 'CMV', 'EBV', 'HSV',
  'SARS', 'MERS', 'PCR', 'ELISA', 'NGS',
  // Conferences
  'ASH', 'ASCO', 'AACR', 'ESMO', 'AAN', 'ADA', 'ACC', 'AHA', 'JPM',
  // Other
  'USA', 'NYC', 'EAP', 'CRDMO', 'CDO', 'CRO', 'CMC', 'API', 'GMP',
  'DIO', 'STAT', 'JAK', 'BTK', 'BCL', 'CDK', 'PARP', 'HDAC',
  'PI3K', 'AKT', 'MTOR', 'MEK', 'ERK', 'RAF'
]);

// Company to ticker mappings
const COMPANY_TICKER_MAP = {
  'longeveron': 'LGVN',
  'cytodyn': 'CYDY',
  'immix': 'IMMX',
  'immix biopharma': 'IMMX',
  'arcutis': 'ARQT',
  'belite': 'BLTE',
  'belite bio': 'BLTE',
  'cardiff': 'CRDF',
  'cardiff oncology': 'CRDF',
  'greenwich': 'GLSI',
  'greenwich lifesciences': 'GLSI',
  'alvotech': 'ALVO',
  'skye bioscience': 'SKYE',
  'skye bio': 'SKYE',
  'kymera': 'KYMR',
  'kymera therapeutics': 'KYMR',
  'psyence': 'PBM',
  'psyence biomed': 'PBM',
  'cytomed': 'GDTC',
  'cytomed therapeutics': 'GDTC',
  'serina': 'SERA',
  'serina therapeutics': 'SERA',
  'siren': 'SIRN',
  'siren biotechnology': 'SIRN',
  'intelligent bio': 'INBS',
  'genvor': 'GNVR',
  'ose immunotherapeutics': 'OSEP',
  'moderna': 'MRNA',
  'pfizer': 'PFE',
  'biontech': 'BNTX',
  'novavax': 'NVAX',
  'regeneron': 'REGN',
  'vertex': 'VRTX',
  'amgen': 'AMGN',
  'gilead': 'GILD',
  'biogen': 'BIIB',
  'crispr therapeutics': 'CRSP',
  'editas': 'EDIT',
  'intellia': 'NTLA',
  'beam therapeutics': 'BEAM',
  // Private companies
  'mabtech': null,
  'sai life': null,
  'sai life sciences': null
};

for (const item of items) {
  const data = item.json;
  const ticker = (data.ticker || '').trim().toUpperCase();
  const title = (data.title || '').toLowerCase();

  const isValidFormat = /^[A-Z]{1,5}$/.test(ticker);
  const isFalsePositive = FALSE_POSITIVES.has(ticker);

  // Valid ticker - pass through
  if (isValidFormat && !isFalsePositive && ticker.length <= 4) {
    results.push({
      json: { ...data, tickerStatus: 'valid', tickerValidated: true }
    });
    continue;
  }

  // Try mapping
  let correctedTicker = null;
  let matchedCompany = null;

  for (const [company, correctTicker] of Object.entries(COMPANY_TICKER_MAP)) {
    if (title.includes(company.toLowerCase())) {
      correctedTicker = correctTicker;
      matchedCompany = company;
      break;
    }
  }

  if (correctedTicker) {
    results.push({
      json: {
        ...data,
        ticker: correctedTicker,
        tickerStatus: 'corrected',
        tickerCorrectedFrom: ticker,
        tickerValidated: true
      }
    });
  } else if (correctedTicker === null && matchedCompany) {
    // Private company - skip silently
  } else {
    // Needs AI
    results.push({
      json: {
        ...data,
        tickerStatus: 'needs_ai',
        originalTicker: ticker,
        validationReason: isFalsePositive ? 'Known false positive: ' + ticker : 'Invalid or suspicious',
        tickerValidated: false
      }
    });
  }
}

return results;

// Parse Market Data - Stage 1
// Combines Alpaca API response with original event data

const item = $input.item.json;

// Get original event data (passed through from earlier nodes)
const event = item.original || item;

// Build output with all fields
const out = {
  // Event identifiers
  guid: event.guid,
  ticker: event.ticker || item.symbol,
  tickerCorrectedFrom: event.tickerCorrectedFrom || null,
  tickerValidated: event.tickerValidated || false,
  tickerStatus: event.tickerStatus,

  // Event metadata
  source: event.source,
  title: event.title,
  link: event.link,
  pubDate: event.pubDate,
  contentSnippet: event.contentSnippet || '',

  // Layer 1 data
  eventType: event.eventType,
  sentiment: event.sentiment,
  sentimentConfidence: event.sentimentConfidence,
  layer1Decision: event.layer1Decision,
  layer1Reasons: event.layer1Reasons,
  processedAt: event.processedAt,
  id: event.id,

  // Market data metadata
  marketDataValid: false,
  marketDataError: null,
  marketDataSource: 'alpaca',
  marketDataFetched: new Date().toISOString(),

  // Defaults
  bid: 0,
  ask: 0,
  spread: 0,
  spreadPct: 999,
  spreadTier: 'REJECT',
  currentPrice: 0,
  volume: 0,
  avgVolume: 0,
  relativeVolume: 0,
  barsAnalyzed: 0
};

// Parse quote data
const quote = item.quote;
if (quote && quote.bp > 0 && quote.ap > 0) {
  const bid = quote.bp;
  const ask = quote.ap;
  const mid = (bid + ask) / 2;
  const spread = ask - bid;
  const pct = mid > 0 ? (spread / mid) * 100 : 999;

  out.bid = +bid.toFixed(4);
  out.ask = +ask.toFixed(4);
  out.spread = +spread.toFixed(4);
  out.spreadPct = +pct.toFixed(4);
  out.currentPrice = +mid.toFixed(4);

  if (pct <= 0.30) out.spreadTier = 'PREFERRED';
  else if (pct <= 0.80) out.spreadTier = 'ACCEPTABLE';
}

// Parse bars data
const bars = item.bars || [];
if (bars.length >= 2) {
  const latest = bars[bars.length - 1];
  const hist = bars.slice(0, -1);
  const avgVol = hist.reduce((s, b) => s + (b.v || 0), 0) / hist.length;

  out.volume = latest.v || 0;
  out.avgVolume = Math.round(avgVol);
  out.relativeVolume = avgVol > 0 ? +(out.volume / avgVol).toFixed(2) : 0;
  out.barsAnalyzed = bars.length;

  out.openPrice = latest.o || null;
  out.highPrice = latest.h || null;
  out.lowPrice = latest.l || null;
  out.closePrice = latest.c || null;

  if (!out.currentPrice && latest.c) {
    out.currentPrice = +latest.c.toFixed(4);
  }

  if (latest.o && latest.c) {
    out.priceChangePct = +(((latest.c - latest.o) / latest.o) * 100).toFixed(2);
  }
}

// Final validation
out.marketDataValid = out.bid > 0 || out.relativeVolume > 0;
out.passesSpreadFilter = out.spreadTier !== 'REJECT';
out.passesRelVolFilter = out.relativeVolume >= 4.0;
out.passesStage1 = out.passesSpreadFilter;

return { json: out };

// Assign spread tier (redundant safety check)
const item = $input.item.json;
const spreadPct = item.spreadPct || 999;

let spreadTier = item.spreadTier || 'REJECT';
if (spreadPct <= 0.30) spreadTier = 'PREFERRED';
else if (spreadPct <= 0.80) spreadTier = 'ACCEPTABLE';

return {
  ...item,
  spreadTier: spreadTier,
  eligibleForTrade: true,
  stage1PassedAt: new Date().toISOString()
};

// Merge all data: original event + quote + bars
const barsData = $input.item.json;
const originalItems = $('1. Validate & Map Tickers1').all();
const quoteItems = $('Alpaca Quote1').all();

const original = originalItems[$runIndex]?.json || {};
const quoteResponse = quoteItems[$runIndex]?.json || {};

// Extract quote from Alpaca Quote response
const quote = quoteResponse.quote || quoteResponse.body?.quote || null;

// Extract bars from Alpaca Bars response
const bars = barsData.body?.bars || barsData.bars || null;

return {
  json: {
    ...original,
    quote: quote,
    bars: bars
  }
};

// Merge Bars Data with Original Event Data
// Match by symbol/ticker instead of index

const barsResponse = $input.item.json || {};
const symbol = barsResponse.symbol;

// Skip if no valid symbol or bars
if (!symbol || symbol === 'NULL' || !barsResponse.bars || barsResponse.bars.length === 0) {
  return null;
}

// Find the original item by matching ticker
const originalItems = $('Fetch Stage 1 Passed').all();
const original = originalItems.find(item => item.json.ticker === symbol)?.json;

// If no matching original found, skip
if (!original || !original.guid) {
  return null;
}

const bars = barsResponse.bars || [];
const latestBar = bars.length > 0 ? bars[bars.length - 1] : null;

return {
  // Preserve ALL original event data
  guid: original.guid,
  ticker: original.ticker,
  tickerCorrectedFrom: original.tickerCorrectedFrom,
  eventType: original.eventType,
  title: original.title,
  source: original.source,
  link: original.link,
  pubDate: original.pubDate,
  sentiment: original.sentiment,
  sentimentConfidence: original.sentimentConfidence,
  layer1Decision: original.layer1Decision,
  layer1Reasons: original.layer1Reasons,
  relativeVolume: original.relativeVolume,
  priceChangePct: original.priceChangePct,
  spreadTier: original.spreadTier,
  spreadPct: original.spreadPct,
  passesStage1: original.passesStage1,
  stage: original.stage,
  stage1PassedAt: original.stage1PassedAt,
  currentPrice: original.currentPrice,
  bid: original.bid,
  ask: original.ask,
  spread: original.spread,

  // Pass the bars data for VWAP calculation
  bars: bars,
