};

// Mock LLM Response - Simulates AI Trading Analyst output

const item = $input.item.json;

if (!item) {
  return null;
}

const hasValidIdentifiers = item.guid && item.ticker;

// Extract data
const sentiment = item.sentiment || 'neutral';
const sentimentConfidence = item.sentimentConfidence || 0;
const vwapPosition = item.vwapPosition || null;
const vwapDeviation = item.vwapDeviation || 0;
const spreadTier = item.spreadTier || 'REJECT';
const spreadPct = item.spreadPct || 0;
const relVol = item.relativeVolume || 0;
const eventType = item.eventType || 'OTHER';
const currentPrice = item.currentPrice || 0;
const aggressorRatio = item.aggressorRatio || 0.5;

let recommendation = 'HOLD';
let confidence = 0.5;
let reasoning = [];
let riskLevel = 'MEDIUM';

// Missing data check
if (!hasValidIdentifiers) {
  return {
    guid: item.guid,
    ticker: item.ticker,
    eventType: eventType,
    title: item.title || null,
    source: item.source || null,
    sentiment: sentiment,
    sentimentConfidence: sentimentConfidence,
    spreadTier: spreadTier,
    spreadPct: spreadPct,
    currentPrice: currentPrice,
    vwapPosition: vwapPosition,
    llmRecommendation: 'SKIP',
    llmConfidence: 0,
    llmReasoning: 'Missing guid or ticker - invalid entry',
    llmRiskLevel: 'N/A',
    llmModel: 'MOCK_v1.0',
    llmAnalyzedAt: new Date().toISOString(),
    suggestedEntry: null,
    suggestedStop: null,
    suggestedTarget: null,
    riskRewardRatio: null,
    tradeSummary: 'SKIP | Invalid data'
  };
}

// === DISQUALIFIERS ===
if (spreadTier === 'REJECT' || spreadPct > 5 || spreadPct < 0) {
  recommendation = 'AVOID';
  confidence = 0.85;
  reasoning.push(`Spread disqualifies trade (${spreadPct.toFixed(2)}% / ${spreadTier})`);
  riskLevel = 'HIGH';
}

if (currentPrice <= 0) {
  recommendation = 'AVOID';
  confidence = 0.9;
  reasoning.push('No valid price data available');
  riskLevel = 'HIGH';
}

if (sentiment === 'negative') {
  recommendation = 'AVOID';
  confidence = 0.75;
  reasoning.push('Negative sentiment detected');
  riskLevel = 'HIGH';
}

// === POSITIVE SIGNALS ===
if (recommendation !== 'AVOID') {

  if (sentiment === 'positive') {
    confidence += 0.1;
    reasoning.push(`Positive sentiment (${(sentimentConfidence * 100).toFixed(0)}% confidence)`);

    if (sentimentConfidence >= 0.8) {
      confidence += 0.1;
      reasoning.push('High sentiment confidence');
    }
  }

  const highValueEvents = ['FDA_APPROVAL', 'TRIAL_PHASE3', 'PARTNERSHIP', 'ACQUISITION'];
  const mediumValueEvents = ['TRIAL_PHASE2', 'BREAKTHROUGH_THERAPY', 'FAST_TRACK'];

  if (highValueEvents.includes(eventType)) {
    confidence += 0.15;
    reasoning.push(`High-value catalyst: ${eventType}`);
    riskLevel = 'MEDIUM';
  } else if (mediumValueEvents.includes(eventType)) {
    confidence += 0.1;
    reasoning.push(`Medium-value catalyst: ${eventType}`);
  }

  if (vwapPosition === 'BELOW_VWAP' || vwapPosition === 'BELOW_1SD') {
    recommendation = 'BUY';
    confidence += 0.1;
    reasoning.push(`Price below VWAP - potential entry`);
    riskLevel = 'LOW';
  } else if (vwapPosition === 'ABOVE_2SD') {
    recommendation = 'HOLD';
    reasoning.push('Price extended above 2SD - wait for pullback');
    riskLevel = 'HIGH';
  } else if (sentiment === 'positive' && spreadTier === 'PREFERRED') {
    recommendation = 'BUY';
    confidence += 0.1;
    reasoning.push('Good spread with positive sentiment');
  } else if (sentiment === 'positive' && spreadTier === 'ACCEPTABLE') {
    recommendation = 'BUY';
    confidence += 0.05;
    reasoning.push('Acceptable spread with positive sentiment');
  }

  if (relVol >= 4) {
    confidence += 0.1;
    reasoning.push(`High relative volume (${relVol.toFixed(1)}x)`);
  }

  if (aggressorRatio >= 0.6) {
    confidence += 0.05;
    reasoning.push(`Buyers in control (${(aggressorRatio * 100).toFixed(0)}%)`);
  }

  if (spreadTier === 'PREFERRED') {
    confidence += 0.05;
    reasoning.push('Excellent spread for entry');
  }
}

confidence = Math.min(0.95, Math.max(0.1, confidence));

let suggestedEntry = null;
let suggestedStop = null;
let suggestedTarget = null;
let riskRewardRatio = null;

if (recommendation === 'BUY' && currentPrice > 0) {
  suggestedEntry = currentPrice;
  suggestedStop = parseFloat((currentPrice * 0.93).toFixed(4));
  suggestedTarget = parseFloat((currentPrice * 1.15).toFixed(4));
  riskRewardRatio = '1:2.1';
}

if (reasoning.length === 0) {
  reasoning.push('Insufficient data for strong recommendation');
}

// Return ONLY the fields needed for llm_analysis table
return {
  // Match keys
  guid: item.guid,
  ticker: item.ticker,

  // Context fields
  eventType: eventType,
  title: item.title || null,
  source: item.source || null,
  sentiment: sentiment,
  sentimentConfidence: sentimentConfidence,
  spreadTier: spreadTier,
  spreadPct: spreadPct,
  currentPrice: currentPrice,
  vwapPosition: vwapPosition,

  // LLM analysis fields
  llmRecommendation: recommendation,
  llmConfidence: parseFloat(confidence.toFixed(2)),
  llmReasoning: reasoning.join('; '),
  llmRiskLevel: riskLevel,
  llmModel: 'MOCK_v1.0',
  llmAnalyzedAt: new Date().toISOString(),

  // Trade plan
  suggestedEntry: suggestedEntry,
  suggestedStop: suggestedStop,
  suggestedTarget: suggestedTarget,
  riskRewardRatio: riskRewardRatio,
  tradeSummary: `${recommendation} | ${(confidence * 100).toFixed(0)}% conf | Risk: ${riskLevel}`
};
